1	import { readFile, unlink } from "node:fs/promises";
2	import path from "node:path";
3	import { config } from "./config.js";
4	import { loadFacts, buildPreambleWithBreakdown, buildLocalPreamble } from "./memory.js";
5	import { petState } from "./pet-server.js";
6	import { AcpProvider, DirectProvider, resolveBaseUrl, type Provider, type ProviderType, type SessionUpdate } from "./provider/index.js";
7	
8	export interface HistoryEntry {
9	  role: "user" | "assistant";
10	  text: string;
11	  timestamp: number;
12	}
13	
14	/**
15	 * Per-Telegram-chat session. Each chat owns its own Kiro ACP subprocess,
16	 * so conversations stay isolated.
17	 */
18	export interface ChatSession {
19	  chatId: number;
20	  userId?: number;
21	  client: Provider;
22	  /** Which provider type is active for this session. */
23	  activeProvider: ProviderType;
24	  sessionId: string;
25	  lastUsed: number;
26	  /** Accumulated assistant text for the in-flight turn. */
27	  buffer: string;
28	  /** Accumulated thinking text for the in-flight turn (local model only). */
29	  thinkingBuffer?: string;
30	  /** Human-readable tool/status lines for the in-flight turn. */
31	  toolLog: string[];
32	  /** Rolling buffer of the agent's latest stderr output. */
33	  stderrTail: string;
34	  /** Called whenever new streamed text is appended. */
35	  onUpdate?: (session: ChatSession) => void;
36	  /** Conversation history for /save export. */
37	  history: HistoryEntry[];
38	  /** Cumulative characters sent by user (approximate context-in). */
39	  charsIn: number;
40	  /** Cumulative characters emitted by agent (approximate context-out). */
41	  charsOut: number;
42	  /** Latest usage meta reported by agent (tokens, etc.), if any. */
43	  usage?: Record<string, unknown>;
44	  /** Long-term memory preamble to inject on first prompt. */
45	  memoryPreamble: string;
46	  /**
47	   * Char-length breakdown of `memoryPreamble`. Captured once at session
48	   * create so the /context and streaming-footer UI can show where the
49	   * preamble tokens are going (tool notes / env block / memory block)
50	   * without having to re-measure the string.
51	   */
52	  preambleBreakdown: {
53	    total: number;
54	    toolNotes: number;
55	    envBlock: number;
56	    memoryBlock: number;
57	    dailylogBlock: number;
58	  };
59	  /** Set true after first prompt so we inject preamble only once. */
60	  preambleInjected: boolean;
61	  /** Stripped tail facts from preamble — used by memory-recall dedup. */
62	  tailFacts: Set<string>;
63	  /** Wiki slugs already injected this session — skip on subsequent turns. */
64	  injectedWikiSlugs: Set<string>;
65	  /** Skill names already injected this session — skip on subsequent turns. */
66	  injectedSkills: Set<string>;
67	  /**
68	   * True while a session/prompt call is in-flight against this session's
69	   * ACP client. kiro-cli rejects concurrent prompts with
70	   * `-32603 Prompt already in progress`; callers must check this flag
71	   * before calling `client.prompt()` and bail out with a friendly message
72	   * instead of racing.
73	   */
74	  inflight: boolean;
75	  /** Internal: inactivity timer handle for the current turn. */
76	  _inactivityTimer?: NodeJS.Timeout;
77	  /** Internal: true while a tool_call has started but not yet completed/failed. */
78	  _toolInFlight?: boolean;
79	  /** Internal: RELAY_DELEGATE tokens captured during streaming (workaround for CLI stripping tokens from final text). */
80	  _streamingDelegates?: string[];
81	  /** Path of the most recent user upload in this turn (consumed by RELAY_DELEGATE auto-attach). */
82	  _lastUploadPath?: string;
83	  /** Internal: meta prompts queued while session was inflight (e.g. parallel delegate results). Drained after inflight=false. */
84	  _pendingMetaQueue: Array<{ ctx: unknown; prompt: string; opts: Record<string, unknown> }>;
85	  /** Internal: consecutive tool call failures for reflexion hint injection. */
86	  _consecutiveToolFails: number;
87	}
88	
89	export class SessionManager {
90	  private sessions = new Map<number, ChatSession>();
91	  private sweeper: NodeJS.Timeout;
92	  /** Per-chat: messages with date <= this value are silently dropped. */
93	  private _dropBefore = new Map<number, number>();
94	  /** Called before a session's agent is closed. Used for memory extraction. */
95	  public onBeforeClose?: (session: ChatSession) => Promise<void>;
96	  /** Called when the agent exits unexpectedly (crash, kill). Best-effort persistence only. */
97	  public onUnexpectedExit?: (session: ChatSession, code: number | null) => Promise<void>;
98	
99	  constructor() {
100	    this.sweeper = setInterval(() => this.sweepIdle(), 60_000);
101	    this.sweeper.unref?.();
102	  }
103	
104	  async get(chatId: number, userId?: number): Promise<ChatSession> {
105	    const existing = this.sessions.get(chatId);
106	    if (existing && !existing.client.isClosed) {
107	      existing.lastUsed = Date.now();
108	      return existing;
109	    }
110	    return this.create(chatId, userId);
111	  }
112	
113	  private async create(chatId: number, userId?: number, providerType?: ProviderType): Promise<ChatSession> {
114	    // Inject TG_ACTIVE_USER_ID so MCP children (mcp-memory) know whose
115	    // facts file to write. MEMORY_DIR is passed through too so the mcp
116	    // server doesn't need to re-read .env.
117	    const env: Record<string, string> = { MEMORY_DIR: config.memoryDir };
118	    if (userId) env.TG_ACTIVE_USER_ID = String(userId);
119	
120	    const activeType = providerType ?? config.defaultProvider;
121	    const facts = userId ? await loadFacts(userId) : "";
122	
123	    // Try to compress recent facts via local LLM (graceful fallback if unavailable)
124	    let compressed: string | null = null;
125	    if (facts && activeType !== "local") {
126	      const lines = facts.split(/\r?\n/).filter(l => l.trim().length > 0);
127	      const tail = config.memoryPreambleTail;
128	      if (lines.length > tail) {
129	        const { compressFactsForPreamble: compress } = await import("./local-llm.js");
130	        compressed = await compress(lines.slice(-tail));
131	      }
132	    }
133	    const breakdown = activeType === "local"
134	      ? buildLocalPreamble(facts, userId)
135	      : buildPreambleWithBreakdown(facts, userId, { compressed });
136	
137	    // Inject working-state from previous session if available (one-shot).
138	    const wsPath = path.join(config.memoryDir, `working-state-${chatId}.md`);
139	    let workingStateBlock = "";
140	    try {
141	      const ws = await readFile(wsPath, "utf8");
142	      workingStateBlock =
143	        "\n[Previous session working state — use as context to resume work]\n" +
144	        ws +
145	        "\nResume from `next_action` above. Do not ask what was done last time.\n" +
146	        "[End working state]\n\n";
147	      await unlink(wsPath);
148	      console.log(`[session] injected working-state for chat ${chatId}`);
149	    } catch { /* file doesn't exist — normal */ }
150	
151	    const preambleText = breakdown.text + workingStateBlock;
152	    const provider = this.createProvider(activeType, env, preambleText);
153	    const session: ChatSession = {
154	      chatId,
155	      userId,
156	      client: provider,
157	      activeProvider: activeType,
158	      sessionId: "",
159	      lastUsed: Date.now(),
160	      buffer: "",
161	      toolLog: [],
162	      stderrTail: "",
163	      history: [],
164	      charsIn: 0,
165	      charsOut: 0,
166	      memoryPreamble: preambleText,
167	      preambleBreakdown: {
168	        total: preambleText.length,
169	        toolNotes: breakdown.toolNotes,
170	        envBlock: breakdown.envBlock,
171	        memoryBlock: breakdown.memoryBlock,
172	        dailylogBlock: breakdown.dailylogBlock,
173	      },
174	      preambleInjected: activeType !== "acp" ? true : false, // Direct providers use system message; ACP needs user-message injection
175	      tailFacts: breakdown.tailFacts,
176	      injectedWikiSlugs: new Set(),
177	      injectedSkills: new Set(),
178	      inflight: false,
179	      _pendingMetaQueue: [],
180	      _consecutiveToolFails: 0,
181	    };
182	
183	    provider.on("update", (u: SessionUpdate) => this.applyUpdate(session, u));
184	    provider.on("stderr", (chunk) => {
185	      // Keep the tail so we can surface it with error messages.
186	      session.stderrTail = (session.stderrTail + chunk).slice(-2000);
187	      // Surface only when debugging; keep quiet otherwise.
188	      if (process.env.DEBUG_ACP) {
189	        console.error(`[acp ${chatId}] ${chunk.trimEnd()}`);
190	      }
191	    });
192	    provider.on("exit", (code) => {
193	      console.error(`[acp ${chatId}] agent exited (code=${code})`);
194	      // Only fire the unexpected-exit hook if this session is still registered.
195	      // Planned shutdowns (drop/sweepIdle/shutdown) remove it from the map first.
196	      const stillRegistered = this.sessions.get(chatId) === session;
197	      if (stillRegistered) {
198	        this.sessions.delete(chatId);
199	        if (this.onUnexpectedExit) {
200	          this.onUnexpectedExit(session, code).catch((e) =>
201	            console.error(`[session ${chatId}] onUnexpectedExit failed:`, e),
202	          );
203	        }
204	      }
205	    });
206	
207	    session.sessionId = await provider.initialize();
208	    this.sessions.set(chatId, session);
209	    return session;
210	  }
211	
212	  /** Factory: create the right Provider based on type. */
213	  private createProvider(type: ProviderType, env: Record<string, string>, systemPrompt?: string): Provider {
214	    if (type === "acp") {
215	      return new AcpProvider({
216	        command: config.agent.command,
217	        args: config.agent.args,
218	        cwd: config.sessionCwd,
219	        env,
220	        promptRetries: config.acpPromptRetries,
221	        promptRetryBaseMs: config.acpPromptRetryBaseMs,
222	        sessionCwd: config.sessionCwd,
223	      });
224	    }
225	    // All other types use DirectProvider
226	    const modelKey = type as keyof typeof config.models;
227	    const apiKeyKey = type as keyof typeof config.apiKeys;
228	    return new DirectProvider({
229	      type,
230	      model: config.models[modelKey] ?? config.models.local,
231	      baseUrl: resolveBaseUrl(type, config.ollamaUrl),
232	      apiKey: config.apiKeys[apiKeyKey] ?? "",
233	      systemPrompt,
234	      mcpEnv: env,
235	      // Local models have limited context — only give them memory tools.
236	      mcpServerFilter: type === "local" ? ["memory", "notebooklm"] : undefined,
237	    });
238	  }
239	
240	  /**
241	   * Switch the active provider for a chat. Closes the old session and
242	   * creates a new one with the specified provider type.
243	   * Returns the new session.
244	   */
245	  async switchProvider(chatId: number, type: ProviderType, userId?: number): Promise<ChatSession> {
246	    const existing = this.sessions.get(chatId);
247	    if (existing) {
248	      this.sessions.delete(chatId);
249	      await existing.client.close().catch(() => {});
250	    }
251	    return this.create(chatId, userId, type);
252	  }
253	
254	  /** Start (or restart) the inactivity timer for a turn. */
255	  startInactivityTimer(session: ChatSession) {
256	    this.clearInactivityTimer(session);
257	    const ms = session._toolInFlight && config.turnToolInactivityTimeoutMs > 0
258	      ? config.turnToolInactivityTimeoutMs
259	      : config.turnInactivityTimeoutMs;
260	    if (ms <= 0) return;
261	    session._inactivityTimer = setTimeout(() => {
262	      console.warn(
263	        `[session ${session.chatId}] turn inactivity timeout (${ms}ms, toolInFlight=${!!session._toolInFlight}) — auto-cancelling`,
264	      );
265	      session.client.cancel();
266	    }, ms);
267	    session._inactivityTimer.unref?.();
268	  }
269	
270	  private resetInactivityTimer(session: ChatSession) {
271	    if (!session._inactivityTimer) return;
272	    this.startInactivityTimer(session);
273	  }
274	
275	  clearInactivityTimer(session: ChatSession) {
276	    if (session._inactivityTimer) {
277	      clearTimeout(session._inactivityTimer);
278	      session._inactivityTimer = undefined;
279	    }
280	  }
281	
282	  private applyUpdate(session: ChatSession, u: SessionUpdate) {
283	    this.resetInactivityTimer(session);
284	    const up = u.update;
285	    // Opportunistically capture usage-like meta the agent may attach.
286	    const meta = (up as { _meta?: Record<string, unknown> })._meta;
287	    const usage =
288	      (meta?.usage as Record<string, unknown> | undefined) ??
289	      ((up as { usage?: Record<string, unknown> }).usage);
290	    if (usage && typeof usage === "object") {
291	      session.usage = usage;
292	    }
293	    switch (up.sessionUpdate) {
294	      case "agent_message_chunk":
295	      case "agent_thought_chunk": {
296	        const content = up.content as { type?: string; text?: string } | undefined;
297	        if (content?.type === "text" && typeof content.text === "string") {
298	          const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
299	          if (up.sessionUpdate === "agent_thought_chunk") {
300	            session.thinkingBuffer = (session.thinkingBuffer || "") + content.text;
301	          } else {
302	            session.buffer += content.text;
303	            session.charsOut += content.text.length;
304	          }
305	          if (wasEmpty) petState("streaming");
306	          // Early-capture RELAY_DELEGATE tokens during streaming.
307	          // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
308	          // but streaming chunks arrive unfiltered. We capture complete tokens here
309	          // so the final-render path can fall back to them if normal extraction finds nothing.
310	          const RD_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
311	          let m: RegExpExecArray | null;
312	          while ((m = RD_RE.exec(session.buffer)) !== null) {
313	            const token = m[0];
314	            if (!session._streamingDelegates) session._streamingDelegates = [];
315	            if (!session._streamingDelegates.includes(token)) {
316	              session._streamingDelegates.push(token);
317	            }
318	          }
319	          session.onUpdate?.(session);
320	        }
321	        break;
322	      }
323	      case "tool_call": {
324	        const title = (up.title as string) ?? "tool";
325	        session.toolLog.push(`🔧 ${title}`);
326	        session._toolInFlight = true;
327	        petState("tool", title);
328	        session.onUpdate?.(session);
329	        break;
330	      }
331	      case "tool_call_update": {
332	        const status = up.status as string | undefined;
333	        if (status === "completed") {
334	          session.toolLog.push(`✅ ${(up.toolCallId as string) ?? "tool"}`);
335	          session._toolInFlight = false;
336	          session._consecutiveToolFails = 0;
337	          session.onUpdate?.(session);
338	        } else if (status === "failed") {
339	          session.toolLog.push(`❌ ${(up.toolCallId as string) ?? "tool"}`);
340	          session._toolInFlight = false;
341	          session._consecutiveToolFails++;
342	          if (session._consecutiveToolFails >= 2) {
343	            session.toolLog.push(
344	              `⚠️ [Reflexion hint] ${session._consecutiveToolFails} consecutive tool failures. ` +
345	              `STOP and diagnose: what assumption is wrong? Try a different approach.`
346	            );
347	          }
348	          session.onUpdate?.(session);
349	        }
350	        break;
351	      }
352	      default:
353	        // Ignore plan/user_message_chunk/etc. for the bridge.
354	        break;
355	    }
356	  }
357	
358	  resetTurn(session: ChatSession) {
359	    session.buffer = "";
360	    session.thinkingBuffer = undefined;
361	    session.toolLog = [];
362	    session.stderrTail = "";
363	    session._toolInFlight = false;
364	    session._streamingDelegates = undefined;
365	    this.startInactivityTimer(session);
366	  }
367	
368	  cancel(chatId: number) {
369	    const s = this.sessions.get(chatId);
370	    if (!s) return;
371	    s.client.cancel();
372	    // Force-kill escalation: if inflight doesn't clear within 60s, the CLI
373	    // is wedged. Kill the process and reset state so the user isn't stuck.
374	    if (s.inflight) {
375	      const timer = setTimeout(async () => {
376	        if (!s.inflight) return; // resolved naturally
377	        console.warn(`[cancel] chat ${chatId} still inflight after 60s — force-killing`);
378	        s.inflight = false;
379	        s._toolInFlight = false;
380	        this.clearInactivityTimer(s);
381	        await s.client.close();
382	      }, 60_000);
383	      timer.unref?.();
384	    }
385	  }
386	
387	  /** Enable drop-all mode: silently discard messages sent before now. */
388	  enableDropAll(chatId: number) { this._dropBefore.set(chatId, Math.floor(Date.now() / 1000)); }
389	  /** Disable drop-all mode. */
390	  disableDropAll(chatId: number) { this._dropBefore.delete(chatId); }
391	  /** Check if a message should be dropped (sent before the cutoff). */
392	  shouldDrop(chatId: number, messageDate: number): boolean {
393	    const cutoff = this._dropBefore.get(chatId);
394	    if (!cutoff) return false;
395	    if (messageDate <= cutoff) return true;
396	    // Message is newer than cutoff — auto-clear and let it through
397	    this._dropBefore.delete(chatId);
398	    return false;
399	  }
400	
401	  peek(chatId: number): ChatSession | undefined {
402	    return this.sessions.get(chatId);
403	  }
404	
405	  size(): number {
406	    return this.sessions.size;
407	  }
408	
409	  async drop(chatId: number) {
410	    const s = this.sessions.get(chatId);
411	    if (!s) return;
412	    this.sessions.delete(chatId);
413	    if (this.onBeforeClose) {
414	      try { await this.onBeforeClose(s); } catch (e) {
415	        console.error(`[session ${chatId}] onBeforeClose failed:`, e);
416	      }
417	    }
418	    await s.client.close();
419	  }
420	
421	  private async sweepIdle() {
422	    const now = Date.now();
423	    for (const [chatId, s] of this.sessions) {
424	      if (now - s.lastUsed > config.sessionIdleMs) {
425	        console.log(`[session] dropping idle chat ${chatId}`);
426	        this.sessions.delete(chatId);
427	        if (this.onBeforeClose) {
428	          try { await this.onBeforeClose(s); } catch (e) {
429	            console.error(`[session ${chatId}] onBeforeClose failed:`, e);
430	          }
431	        }
432	        s.client.close().catch(() => {});
433	      }
434	    }
435	  }
436	
437	  async shutdown() {
438	    clearInterval(this.sweeper);
439	    const all = Array.from(this.sessions.values());
440	    this.sessions.clear();
441	    console.log(`[session] shutdown: flushing ${all.length} session(s)`);
442	    if (this.onBeforeClose) {
443	      for (const s of all) {
444	        if (s.client.isClosed) {
445	          console.log(`[session] shutdown: skipping already-closed chat ${s.chatId}`);
446	          continue;
447	        }
448	        console.log(`[session] shutdown: running onBeforeClose for chat ${s.chatId} (history=${s.history.length})`);
449	        try { await this.onBeforeClose(s); } catch (e) {
450	          console.error(`[session ${s.chatId}] onBeforeClose failed:`, e);
451	        }
452	      }
453	    }
454	    await Promise.all(all.map((s) => s.client.isClosed ? Promise.resolve() : s.client.close()));
455	    console.log(`[session] shutdown: done`);
456	  }
457	}
