import "dotenv/config";
import { execSync } from "node:child_process";
import path from "node:path";
import type { ProviderType } from "./provider/types.js";

function required(name: string): string {
  const v = process.env[name];
  if (!v || v.trim() === "") {
    throw new Error(`Missing required env var: ${name}`);
  }
  return v;
}

function parseCommand(raw: string): { command: string; args: string[] } {
  const parts = raw.trim().split(/\s+/);
  if (parts.length === 0) {
    throw new Error("ACP_AGENT_COMMAND is empty");
  }
  return { command: parts[0], args: parts.slice(1) };
}

function buildAgent(): { command: string; args: string[] } {
  const base = parseCommand(process.env.ACP_AGENT_COMMAND ?? "kiro-cli acp");
  const name = (process.env.ACP_AGENT_NAME ?? "").trim();
  if (name && !base.args.includes("--agent")) {
    base.args.push("--agent", name);
  }
  return base;
}

export const config = {
  telegramToken: required("TELEGRAM_BOT_TOKEN"),
  agent: buildAgent(),
  sessionCwd: path.resolve(
    process.env.ACP_SESSION_CWD && process.env.ACP_SESSION_CWD.trim() !== ""
      ? process.env.ACP_SESSION_CWD
      : process.cwd()
  ),
  allowedUserIds: (process.env.ALLOWED_USER_IDS ?? "")
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean)
    .map((s) => Number(s))
    .filter((n) => Number.isFinite(n)),
  sessionIdleMs:
    Number(process.env.SESSION_IDLE_MINUTES ?? "30") * 60 * 1000,
  contextWindowTokens:
    Number(process.env.CONTEXT_WINDOW_TOKENS ?? "200000"),
  sendFileRoots: (process.env.TG_SEND_ROOTS ?? "")
    .split(path.delimiter)
    .map((s) => s.trim())
    .filter(Boolean)
    .map((s) => path.resolve(s)),
  memoryDir: path.resolve(
    process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
      ? process.env.MEMORY_DIR
      : "F:\\AI\\AIMemory"
  ),
  // Topic classification rules file (see src/topic-rules.ts). Defaults to
  // <memoryDir>/topics.json so it's auto-included in /backup. Set
  // TOPICS_FILE to override. If the file is missing it is auto-created
  // from the built-in defaults on bridge startup.
  topicsFile: path.resolve(
    process.env.TOPICS_FILE && process.env.TOPICS_FILE.trim() !== ""
      ? process.env.TOPICS_FILE
      : path.join(
          process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
            ? process.env.MEMORY_DIR
            : "F:\\AI\\AIMemory",
          "topics.json"
        )
  ),
  // How long to wait for the agent's fact-extraction reply before giving up
  // and queueing the transcript for a later retry. This is a safety fuse —
  // normally extraction finishes well within this window. If it trips, the
  // transcript is queued and retried on the next bot startup.
  memoryExtractTimeoutMs:
    Number(process.env.MEMORY_EXTRACT_TIMEOUT_MS ?? "180000"),
  // Transient errors from the agent's cloud backend (e.g. AWS Bedrock
  // "dispatch failure" mid-stream) are retried automatically. 0 disables.
  acpPromptRetries:
    Math.max(0, Number(process.env.ACP_PROMPT_RETRIES ?? "2")),
  // Initial backoff before the first retry (ms). Doubles each attempt.
  acpPromptRetryBaseMs:
    Math.max(0, Number(process.env.ACP_PROMPT_RETRY_BASE_MS ?? "1000")),
  // How often (ms) the streaming reply message is edited. Higher = less
  // frequent updates, less likely to hit Telegram 429 rate-limit. Default
  // 1200ms; raise to 2000-3000 if 429s happen.
  streamEditIntervalMs:
    Math.max(500, Number(process.env.STREAM_EDIT_INTERVAL_MS ?? "1200")),
  // Max seconds grammY autoRetry will wait for Telegram 429 retry_after
  // before giving up. Default 60s; Telegram escalates penalties for
  // repeat offenders up to 120s+, so 60 covers most realistic cases.
  telegramAutoRetryMaxDelaySeconds:
    Math.max(5, Number(process.env.TG_AUTORETRY_MAX_DELAY_SECONDS ?? "60")),
  // Working tree for /backup. Empty string (or unset) disables the feature.
  // Must be a pre-existing git repo with an "origin" remote. Bootstrap with:
  //   gh repo create <name> --private --source=. --remote=origin --push
  // (Earlier versions defaulted to F:\AI\ai-memory-backup; that default was
  // removed because it silently pointed other machines at the Kiro box's
  // path and caused confusing "not a git repo" errors.)
  backupRepoDir: (() => {
    const raw = process.env.BACKUP_REPO_DIR;
    if (raw === undefined || raw.trim() === "") return "";
    return path.resolve(raw);
  })(),
  backupBranch: (process.env.BACKUP_BRANCH ?? "main").trim() || "main",
  // How many of the most-recent facts to inject verbatim into each new
  // session's preamble. Older facts are summarised as a topic index and
  // retrieved on demand via the `list_facts` MCP tool. Set to 0 to inject
  // everything (old behaviour). Default 30.
  memoryPreambleTail:
    Math.max(0, Number(process.env.MEMORY_PREAMBLE_TAIL ?? "5")),
  // Whether to append a topic index of older facts after the tail block.
  // "1"/"true" enables; anything else disables. Default enabled.
  memoryPreambleTopics: (() => {
    const raw = (process.env.MEMORY_PREAMBLE_TOPICS ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  // Maximum number of topics allowed in topics.json. Enforced by the
  // apply_topics MCP tool when the agent proposes a new layout. Default
  // 50. A non-positive value means "no user-configured limit" but there
  // is still a hard cap of 200 in facts-store.ts to prevent absurd
  // proposals. Change this if the user's fact set is large enough that
  // 50 topics becomes cramped.
  memoryMaxTopics: (() => {
    const raw = (process.env.MEMORY_MAX_TOPICS ?? "").trim();
    const n = raw ? Number(raw) : NaN;
    return Number.isFinite(n) && n > 0 ? Math.floor(n) : 50;
  })(),
  // Default turn budget for /goal when the user doesn't specify one.
  // Must be a positive integer; values >50 are clamped to 50 (hard cap
  // to prevent runaway loops). Invalid or missing values fall back to 5.
  // Per-goal override via `/goal <N> <objective>` is not wired up yet —
  // this env var is the single lever for now.
  goalDefaultMaxTurns: (() => {
    const raw = (process.env.GOAL_DEFAULT_MAX_TURNS ?? "").trim();
    const n = raw ? Number(raw) : NaN;
    if (!Number.isFinite(n) || n < 1) return 5;
    return Math.min(50, Math.floor(n));
  })(),
  // If the agent produces no session/update for this many ms during an
  // in-flight turn, the bridge auto-cancels the turn. Prevents indefinite
  // hangs when a tool call stalls inside the agent. 0 disables. Default 3min.
  turnInactivityTimeoutMs:
    Math.max(0, Number(process.env.TURN_INACTIVITY_TIMEOUT_MS ?? "180000")),
  // Longer timeout used while a tool_call is in progress (no completed/failed
  // status yet). Tools like shell (ffmpeg, whisper, yt-dlp) can legitimately
  // run for minutes. 0 falls back to turnInactivityTimeoutMs. Default 10min.
  turnToolInactivityTimeoutMs:
    Math.max(0, Number(process.env.TURN_TOOL_INACTIVITY_TIMEOUT_MS ?? "600000")),
  // Bot-to-Bot Relay via Upstash Redis + Telegram bot-to-bot
  relay: (() => {
    const url = (process.env.UPSTASH_REDIS_REST_URL ?? "").trim();
    const token = (process.env.UPSTASH_REDIS_REST_TOKEN ?? "").trim();
    const groupChatId = Number(process.env.RELAY_GROUP_CHAT_ID ?? "0");
    const botName = (process.env.RELAY_BOT_NAME ?? "").trim();
    const transport = (process.env.RELAY_TRANSPORT ?? "redis").trim() as "redis" | "telegram" | "both";
    const targetBotUsername = (process.env.RELAY_TARGET_BOT_USERNAME ?? "").trim();
    // Minimum: need botName + groupChatId + at least one transport configured
    const hasRedis = !!(url && token);
    const hasTelegram = !!targetBotUsername;
    if (!groupChatId || !botName) return null;
    if (!hasRedis && !hasTelegram) return null;
    const maxConsecutiveTurns = Number(process.env.RELAY_MAX_CONSECUTIVE_TURNS) || 3;
    return { redisUrl: url, redisToken: token, groupChatId, botName, maxConsecutiveTurns, transport, targetBotUsername };
  })(),
  // Local LLM feature flags. Set to "0"/"false" to disable.
  localLlmPrefilter: (() => {
    const raw = (process.env.LOCAL_LLM_PREFILTER ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  localLlmRerank: (() => {
    const raw = (process.env.LOCAL_LLM_RERANK ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  localLlmIntentFallback: (() => {
    const raw = (process.env.LOCAL_LLM_INTENT_FALLBACK ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  // RTK (Rust Token Killer) shell rewrite. When enabled, preamble instructs
  // the agent to prefix shell commands with `rtk` for token-compressed output.
  // Requires rtk binary in PATH. Set to "0"/"false" to disable.
  rtkShellRewrite: (() => {
    const raw = (process.env.RTK_SHELL_REWRITE ?? "0").trim().toLowerCase();
    const wanted = raw === "1" || raw === "true" || raw === "yes";
    if (!wanted) return false;
    // Verify rtk is actually reachable
    try {
      execSync("rtk --version", { encoding: "utf8", timeout: 3000, stdio: "pipe" });
      return true;
    } catch {
      console.warn("[config] RTK_SHELL_REWRITE=1 but `rtk` not found in PATH — disabled");
      return false;
    }
  })(),
  // ─── Multi-Model Provider ─────────────────────────────────────────────────
  // Which provider to use on startup. "acp" = Kiro CLI subprocess (default).
  defaultProvider: (process.env.DEFAULT_PROVIDER ?? "acp").trim().toLowerCase() as ProviderType,
  // Model identifiers per provider (used by DirectProvider, ignored by ACP).
  models: {
    anthropic: (process.env.ANTHROPIC_MODEL ?? "claude-sonnet-4-20250514").trim(),
    openai: (process.env.OPENAI_MODEL ?? "gpt-4o").trim(),
    gemini: (process.env.GEMINI_MODEL ?? "gemini-2.5-flash").trim(),
    deepseek: (process.env.DEEPSEEK_MODEL ?? "deepseek-chat").trim(),
    groq: (process.env.GROQ_MODEL ?? "llama-3.3-70b-versatile").trim(),
    local: (process.env.OLLAMA_CHAT_MODEL ?? "qwen3.6:35b-a3b").trim(),
  },
  // API keys (read at runtime; empty = provider unavailable).
  apiKeys: {
    anthropic: (process.env.ANTHROPIC_API_KEY ?? "").trim(),
    openai: (process.env.OPENAI_API_KEY ?? "").trim(),
    gemini: (process.env.GEMINI_API_KEY ?? "").trim(),
    deepseek: (process.env.DEEPSEEK_API_KEY ?? "").trim(),
    groq: (process.env.GROQ_API_KEY ?? "").trim(),
  },
  // Ollama base URL (also used by DirectProvider "local" mode).
  ollamaUrl: (process.env.OLLAMA_URL ?? "http://127.0.0.1:11434").trim(),
  // llama.cpp server URL. When set, "local" mode uses this instead of Ollama.
  llamaCppUrl: (process.env.LLAMACPP_URL ?? "").trim(),
  // Status monitoring server port.
  statusPort: Number(process.env.STATUS_PORT ?? "3847"),
};

