1	/**
2	 * Skill suggestion via frequency detection.
3	 * Scans recent sessions for recurring user message patterns that have no
4	 * matching skill, producing a candidate list for /dream memorytoskill.
5	 */
6	import { readdirSync, readFileSync, existsSync, statSync } from "node:fs";
7	import path from "node:path";
8	import { config } from "./config.js";
9	import { detectSkillDir } from "./memory.js";
10	
11	export interface SkillCandidate {
12	  pattern: string;          // representative keyword/phrase
13	  count: number;            // how many sessions it appeared in
14	  examples: string[];       // up to 3 representative user messages
15	}
16	
17	const DAYS_WINDOW = 7;
18	const MIN_SESSIONS = 3;    // must appear in ≥3 different sessions
19	const STOP_WORDS = new Set([
20	  "的", "了", "是", "在", "我", "有", "和", "就", "不", "人", "都", "一", "這",
21	  "那", "要", "會", "對", "也", "說", "到", "可以", "沒有", "什麼", "怎麼",
22	  "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
23	  "have", "has", "had", "do", "does", "did", "will", "would", "could",
24	  "should", "may", "might", "shall", "can", "need", "dare", "ought",
25	  "to", "of", "in", "for", "on", "with", "at", "by", "from", "as",
26	  "into", "through", "during", "before", "after", "above", "below",
27	  "it", "this", "that", "these", "those", "i", "you", "he", "she",
28	  "we", "they", "me", "him", "her", "us", "them", "my", "your",
29	  "his", "its", "our", "their", "and", "but", "or", "not", "no",
30	  "好", "嗯", "ok", "yes", "no", "push", "繼續", "done",
31	]);
32	
33	/** Extract user messages from a session markdown file. */
34	function extractUserMessages(content: string): string[] {
35	  const msgs: string[] = [];
36	  const blocks = content.split(/^### 👤 User/m);
37	  for (let i = 1; i < blocks.length; i++) {
38	    // Take text until next ### header
39	    const end = blocks[i].indexOf("\n### ");
40	    const raw = end > 0 ? blocks[i].slice(0, end) : blocks[i];
41	    // Strip metadata lines (Intent hint, Skill routing, timestamps, relay captions)
42	    const lines = raw.split("\n").filter(l =>
43	      !l.startsWith("[") && !l.startsWith("---") && !l.startsWith("### ") &&
44	      !/^\s*\(.*[上下]午\d/.test(l) &&
45	      !/^\s*這是委派/.test(l) &&
46	      l.trim().length > 2
47	    );
48	    const msg = lines.join(" ").trim();
49	    if (msg.length > 5 && msg.length < 200) msgs.push(msg);
50	  }
51	  return msgs;
52	}
53	
54	/** Tokenize a message into meaningful bigrams. */
55	function extractBigrams(msg: string): string[] {
56	  const words = msg.toLowerCase()
57	    .replace(/[^\w\u4e00-\u9fff\s]/g, " ")
58	    .split(/\s+/)
59	    .filter(w => w.length > 1 && !STOP_WORDS.has(w));
60	  const bigrams: string[] = [];
61	  for (let i = 0; i < words.length - 1; i++) {
62	    bigrams.push(`${words[i]} ${words[i + 1]}`);
63	  }
64	  // Also include single meaningful words ≥3 chars
65	  for (const w of words) {
66	    if (w.length >= 3) bigrams.push(w);
67	  }
68	  return bigrams;
69	}
70	
71	/** Load existing skill keywords for comparison. */
72	function loadSkillKeywords(): Set<string> {
73	  const skillDir = detectSkillDir();
74	  const keywords = new Set<string>();
75	  if (!existsSync(skillDir)) return keywords;
76	  for (const entry of readdirSync(skillDir, { withFileTypes: true })) {
77	    if (!entry.isDirectory()) continue;
78	    // Add the skill folder name as a keyword
79	    keywords.add(entry.name.replace(/^ms-/, "").replace(/-/g, " "));
80	    // Read SKILL.md description for additional keywords
81	    const skillFile = path.join(skillDir, entry.name, "SKILL.md");
