/**
 * Skill suggestion via frequency detection.
 * Scans recent sessions for recurring user message patterns that have no
 * matching skill, producing a candidate list for /dream memorytoskill.
 */
import { readdirSync, readFileSync, existsSync, statSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";
import { detectSkillDir } from "./memory.js";

export interface SkillCandidate {
  pattern: string;          // representative keyword/phrase
  count: number;            // how many sessions it appeared in
  examples: string[];       // up to 3 representative user messages
}

const DAYS_WINDOW = 7;
const MIN_SESSIONS = 3;    // must appear in ≥3 different sessions
const STOP_WORDS = new Set([
  "的", "了", "是", "在", "我", "有", "和", "就", "不", "人", "都", "一", "這",
  "那", "要", "會", "對", "也", "說", "到", "可以", "沒有", "什麼", "怎麼",
  "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
  "have", "has", "had", "do", "does", "did", "will", "would", "could",
  "should", "may", "might", "shall", "can", "need", "dare", "ought",
  "to", "of", "in", "for", "on", "with", "at", "by", "from", "as",
  "into", "through", "during", "before", "after", "above", "below",
  "it", "this", "that", "these", "those", "i", "you", "he", "she",
  "we", "they", "me", "him", "her", "us", "them", "my", "your",
  "his", "its", "our", "their", "and", "but", "or", "not", "no",
  "好", "嗯", "ok", "yes", "no", "push", "繼續", "done",
]);

/** Extract user messages from a session markdown file. */
function extractUserMessages(content: string): string[] {
  const msgs: string[] = [];
  const blocks = content.split(/^### 👤 User/m);
  for (let i = 1; i < blocks.length; i++) {
    // Take text until next ### header
    const end = blocks[i].indexOf("\n### ");
    const raw = end > 0 ? blocks[i].slice(0, end) : blocks[i];
    // Strip metadata lines (Intent hint, Skill routing, timestamps, relay captions)
    const lines = raw.split("\n").filter(l =>
      !l.startsWith("[") && !l.startsWith("---") && !l.startsWith("### ") &&
      !/^\s*\(.*[上下]午\d/.test(l) &&
      !/^\s*這是委派/.test(l) &&
      l.trim().length > 2
    );
    const msg = lines.join(" ").trim();
    if (msg.length > 5 && msg.length < 200) msgs.push(msg);
  }
  return msgs;
}

/** Tokenize a message into meaningful bigrams. */
function extractBigrams(msg: string): string[] {
  const words = msg.toLowerCase()
    .replace(/[^\w\u4e00-\u9fff\s]/g, " ")
    .split(/\s+/)
    .filter(w => w.length > 1 && !STOP_WORDS.has(w));
  const bigrams: string[] = [];
  for (let i = 0; i < words.length - 1; i++) {
    bigrams.push(`${words[i]} ${words[i + 1]}`);
  }
  // Also include single meaningful words ≥3 chars
  for (const w of words) {
    if (w.length >= 3) bigrams.push(w);
  }
  return bigrams;
}

/** Load existing skill keywords for comparison. */
function loadSkillKeywords(): Set<string> {
  const skillDir = detectSkillDir();
  const keywords = new Set<string>();
  if (!existsSync(skillDir)) return keywords;
  for (const entry of readdirSync(skillDir, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;
    // Add the skill folder name as a keyword
    keywords.add(entry.name.replace(/^ms-/, "").replace(/-/g, " "));
    // Read SKILL.md description for additional keywords
    const skillFile = path.join(skillDir, entry.name, "SKILL.md");
    if (!existsSync(skillFile)) continue;
    const content = readFileSync(skillFile, "utf8").slice(0, 500);
    const descMatch = content.match(/description:\s*(.+)/);
    if (descMatch) {
      const desc = descMatch[1].toLowerCase();
      // Extract Chinese/English words from description
      const descWords = desc.replace(/[^\w\u4e00-\u9fff\s]/g, " ").split(/\s+/)
        .filter(w => w.length >= 3);
      for (const w of descWords) keywords.add(w);
    }
  }
  return keywords;
}

/**
 * Scan recent sessions and produce skill candidates.
 * Returns patterns that appear in ≥3 sessions with no matching skill.
 */
export function suggestSkills(): SkillCandidate[] {
  const sessDir = path.join(config.memoryDir, "sessions");
  if (!existsSync(sessDir)) return [];

  const cutoff = Date.now() - DAYS_WINDOW * 86400_000;
  const files = readdirSync(sessDir)
    .filter(f => f.startsWith("session-") && f.endsWith(".md"))
    .filter(f => {
      const full = path.join(sessDir, f);
      try {
        return statSync(full).mtimeMs >= cutoff;
      } catch { return false; }
    });

  // Count bigrams across sessions (deduplicated per session)
  const bigramSessions = new Map<string, Set<string>>(); // bigram → set of session filenames
  const bigramExamples = new Map<string, string[]>();     // bigram → example messages

  for (const file of files) {
    const content = readFileSync(path.join(sessDir, file), "utf8");
    const msgs = extractUserMessages(content);
    const sessionBigrams = new Set<string>();
    for (const msg of msgs) {
      for (const bg of extractBigrams(msg)) {
        if (!sessionBigrams.has(bg)) {
          sessionBigrams.add(bg);
          if (!bigramSessions.has(bg)) bigramSessions.set(bg, new Set());
          bigramSessions.get(bg)!.add(file);
          if (!bigramExamples.has(bg)) bigramExamples.set(bg, []);
          const ex = bigramExamples.get(bg)!;
          if (ex.length < 3) ex.push(msg.slice(0, 100));
        }
      }
    }
  }

  // Filter: ≥MIN_SESSIONS occurrences
  const skillKeywords = loadSkillKeywords();
  const candidates: SkillCandidate[] = [];

  for (const [bigram, sessions] of bigramSessions) {
    if (sessions.size < MIN_SESSIONS) continue;
    // Skip if matches an existing skill keyword
    if (skillKeywords.has(bigram)) continue;
    // Skip if any word in the bigram is a skill keyword
    const words = bigram.split(" ");
    if (words.some(w => skillKeywords.has(w))) continue;

    candidates.push({
      pattern: bigram,
      count: sessions.size,
      examples: bigramExamples.get(bigram) ?? [],
    });
  }

  // Sort by frequency descending, take top 10
  candidates.sort((a, b) => b.count - a.count);
  return candidates.slice(0, 10);
}

