9	// MCP server for long-term memory. Runs as a child of the ACP agent
10	// (spawned via ~/.kiro/agents/main.json mcpServers, or
11	// ~/.codex/config.toml [mcp_servers.memory] for Codex CLI standalone).
12	// Exposes remember / list_facts / forget / apply_topics / propose_topics.
13	//
14	// The active user id is taken from one of these, in priority order:
15	//   1. env TG_ACTIVE_USER_ID  — injected by telegram-kiro bridge
16	//   2. env MEMORY_USER_ID     — static config for standalone agents
17	//   3. file <MEMORY_DIR>/.user-id  — single-line plain text
18	//
19	// MEMORY_DIR env overrides the facts directory (defaults to
20	// F:\AI\AIMemory on Kiro, set to F:\AI_Codex\AIMemory on Codex box).
21	import { mkdir, readFile, appendFile } from "node:fs/promises";
22	import { readFileSync } from "node:fs";
23	import path from "node:path";
24	import { Server } from "@modelcontextprotocol/sdk/server/index.js";
25	import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
26	import {
27	  CallToolRequestSchema,
28	  ListToolsRequestSchema,
29	} from "@modelcontextprotocol/sdk/types.js";
30	import { keywordsForTopic, classifyFact, classifyFactAsync } from "./topic-rules.js";
31	import {
32	  appendFactShardOnly,
33	  readTopicFacts,
34	  formatFactLine,
35	  forgetMatch,
36	  forgetCommit,
37	  readAllFactsForReview,
38	  applyTopics,
39	  computeTopicsToken,
40	  normaliseProposedTopics,
41	  resolveMaxTopics,
42	} from "./facts-store.js";
43	import { factExists, insertFact, deleteFact } from "./memory-db.js";
44	import { ingestPrepare, ingestSave, listIndexes, queryIndex, findStaleIndexes, ingestUpdate, buildCrossRefs } from "./page-index.js";
45	
46	const MEMORY_DIR = path.resolve(
47	  process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
48	    ? process.env.MEMORY_DIR
49	    : "F:\\AI\\AIMemory"
50	);
51	
52	function activeUserId(): number {
53	  // Primary: TG_ACTIVE_USER_ID — set automatically by the telegram-kiro
54	  // bridge when it spawns the agent. Accept the shorter alias
55	  // MEMORY_USER_ID for standalone use (e.g. Codex CLI where the bridge
56	  // doesn't inject env, and the user statically configures the MCP
57	  // server via ~/.codex/config.toml [mcp_servers.memory.env]).
58	  // Finally, fall back to reading <MEMORY_DIR>/.user-id so the user can
59	  // drop a single-line file there instead of editing TOML.
