#!/usr/bin/env node
// Redirect all console output to stderr BEFORE any imports —
// MCP stdio transport requires stdout to be pure JSON-RPC.
console.log = console.error;
console.info = console.error;
console.warn = console.error;
console.debug = console.error;

// MCP server for long-term memory. Runs as a child of the ACP agent
// (spawned via ~/.kiro/agents/main.json mcpServers, or
// ~/.codex/config.toml [mcp_servers.memory] for Codex CLI standalone).
// Exposes remember / list_facts / forget / apply_topics / propose_topics.
//
// The active user id is taken from one of these, in priority order:
//   1. env TG_ACTIVE_USER_ID  — injected by telegram-kiro bridge
//   2. env MEMORY_USER_ID     — static config for standalone agents
//   3. file <MEMORY_DIR>/.user-id  — single-line plain text
//
// MEMORY_DIR env overrides the facts directory (defaults to
// F:\AI\AIMemory on Kiro, set to F:\AI_Codex\AIMemory on Codex box).
import { mkdir, readFile, appendFile } from "node:fs/promises";
import { readFileSync } from "node:fs";
import path from "node:path";
import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { keywordsForTopic, classifyFact, classifyFactAsync } from "./topic-rules.js";
import {
  appendFactShardOnly,
  readTopicFacts,
  formatFactLine,
  forgetMatch,
  forgetCommit,
  readAllFactsForReview,
  applyTopics,
  computeTopicsToken,
  normaliseProposedTopics,
  resolveMaxTopics,
} from "./facts-store.js";
import { factExists, insertFact, deleteFact } from "./memory-db.js";
import { ingestPrepare, ingestSave, listIndexes, queryIndex, findStaleIndexes, ingestUpdate, buildCrossRefs } from "./page-index.js";

const MEMORY_DIR = path.resolve(
  process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
    ? process.env.MEMORY_DIR
    : "F:\\AI\\AIMemory"
);

function activeUserId(): number {
  // Primary: TG_ACTIVE_USER_ID — set automatically by the telegram-kiro
  // bridge when it spawns the agent. Accept the shorter alias
  // MEMORY_USER_ID for standalone use (e.g. Codex CLI where the bridge
  // doesn't inject env, and the user statically configures the MCP
  // server via ~/.codex/config.toml [mcp_servers.memory.env]).
  // Finally, fall back to reading <MEMORY_DIR>/.user-id so the user can
  // drop a single-line file there instead of editing TOML.
  const envRaw =
    (process.env.TG_ACTIVE_USER_ID ?? "").trim() ||
    (process.env.MEMORY_USER_ID ?? "").trim();
  if (envRaw) {
    const n = Number(envRaw);
    if (Number.isFinite(n) && n > 0) return n;
  }
  try {
    const filePath = path.join(MEMORY_DIR, ".user-id");
    const raw = readFileSync(filePath, "utf8").trim();
    const n = Number(raw);
    if (Number.isFinite(n) && n > 0) return n;
  } catch {
    // ignore — fall through to error
  }
  throw new Error(
    "memory MCP: active user id not configured. Set one of:\n" +
      "  - env TG_ACTIVE_USER_ID (how the telegram-kiro bridge normally injects it), or\n" +
      "  - env MEMORY_USER_ID (set in ~/.codex/config.toml [mcp_servers.memory.env] for standalone Codex use), or\n" +
      `  - a plain-text file ${path.join(MEMORY_DIR, ".user-id")} containing just the Telegram user id.`
  );
}

function factsPath(userId: number): string {
  return path.join(MEMORY_DIR, `facts-${userId}.md`);
}

async function remember(text: string, topic?: string): Promise<string> {
  const line = text.trim();
  if (!line) throw new Error("text is empty");
  const userId = activeUserId();
  await mkdir(MEMORY_DIR, { recursive: true });

  // Dedup check: precise content hash (SQLite) then Jaccard fallback.
  const targetTopic = topic?.trim() || (await classifyFactAsync(line)) || "misc";
  if (factExists(line)) {
    return `⚠️ Exact duplicate detected (content hash match). Not appended.`;
  }
  const existingFacts = readTopicFacts(userId, targetTopic);
  const dupWarning = checkDuplicate(line, existingFacts);

  const formatted = formatFactLine(line);
  await appendFile(factsPath(userId), formatted, "utf8");
  // Mirror to topic shard. If caller supplied an explicit topic we trust
  // it; otherwise classifyFact infers from the text.
  const shard = appendFactShardOnly({
    userId,
    formattedLine: formatted,
    rawText: line,
    topic: topic?.trim() || undefined,
  });
  // Mirror to SQLite index
  const createdAt = new Date().toISOString();
  insertFact(line, targetTopic, createdAt);
  const shardNote = shard ? `, shard=${path.basename(shard.file)}` : "";
  const warn = dupWarning ? `\n⚠️ Possible duplicate in shard "${targetTopic}": "${dupWarning}"` : "";
  return `ok: appended to ${factsPath(userId)}${shardNote}${warn}`;
}

function stripFactPrefix(s: string): string {
  return s.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "").trim();
}

/**
 * Check if a new fact is semantically similar to existing facts using
 * Jaccard word-set similarity. Returns the most similar existing fact
 * text if similarity > 0.7, or null if no duplicate found.
 */
function checkDuplicate(newFact: string, existingFacts: string[]): string | null {
  if (existingFacts.length === 0) return null;
  const newWords = wordSet(newFact);
  if (newWords.size < 3) return null; // too short to meaningfully compare
  let bestScore = 0;
  let bestFact = "";
  for (const existing of existingFacts) {
    const existWords = wordSet(existing);
    const intersection = new Set([...newWords].filter((w) => existWords.has(w)));
    const union = new Set([...newWords, ...existWords]);
    const jaccard = union.size > 0 ? intersection.size / union.size : 0;
    if (jaccard > bestScore) {
      bestScore = jaccard;
      bestFact = existing;
    }
  }
  return bestScore >= 0.7 ? bestFact : null;
}

function wordSet(text: string): Set<string> {
  return new Set(
    text.toLowerCase().replace(/[^\w\u4e00-\u9fff]+/g, " ").trim().split(/\s+/).filter(Boolean)
  );

