1	/**
2	 * memory-db.ts — SQLite derived index for facts.
3	 *
4	 * The master log (facts-<userId>.md) remains the source of truth.
5	 * This module maintains a SQLite DB as a derived search index with:
6	 *   - FTS5 full-text search (BM25)
7	 *   - Embedding cache (content hash → vector)
8	 *   - Temporal decay on retrieval
9	 *   - Precise content-hash dedup
10	 *
11	 * Delete the .db file and call syncFactsToDb() to rebuild from .md.
12	 */
13	
14	import Database, { type Database as DatabaseType } from "better-sqlite3";
15	import { createHash } from "node:crypto";
16	import { readFileSync, existsSync } from "node:fs";
17	import path from "node:path";
18	import { resolveMemoryDir, masterFactsFile } from "./facts-store.js";
19	import { classifyFact } from "./topic-rules.js";
20	import { embedText, cosineSim } from "./embed-router.js";
21	
22	// ─── Config ──────────────────────────────────────────────────────────────────
23	
24	const DB_FILENAME = "memory-index.db";
25	const HALF_LIFE_DAYS = 30;
26	const LAMBDA = Math.LN2 / HALF_LIFE_DAYS;
27	const VECTOR_WEIGHT = 0.7;
28	const BM25_WEIGHT = 0.3;
29	const DEFAULT_THRESHOLD = 0.35;
30	const DEFAULT_TOP_K = 15;
31	
32	/**
33	 * Source-tier boost: curated/structured topics get a score multiplier.
34	 * Inspired by GBrain's source-aware ranking where wiki > chat log.
35	 * Topics with wiki pages or lesson-grade content rank higher than misc/transient.
36	 */
37	const SOURCE_TIER_BOOST: Record<string, number> = {
38	  // Tier 1: architecture/design decisions (most curated)
39	  "bridge-arch": 1.3,
40	  "bridge-preamble": 1.3,
41	  "bridge-llm-hybrid": 1.3,
42	  "user-preference": 1.3,
43	  // Tier 2: established subsystems with wiki pages
44	  "bridge-token-protocol": 1.2,
45	  "bridge-embedding-router": 1.2,
46	  "bridge-goal-state": 1.2,
47	  "slot-codegen": 1.2,
48	  "cocos-editor": 1.2,
49	  "local-llm": 1.2,
50	  // Tier 3: default (no boost)
51	  // Tier 4: transient/catchall (slight penalty)
52	  "misc": 0.85,
53	};
54	const DEFAULT_TIER_BOOST = 1.0;
55	
56	// ─── State ───────────────────────────────────────────────────────────────────
57	
58	let db: DatabaseType | null = null;
59	
60	// ─── Public API ──────────────────────────────────────────────────────────────
61	
62	export function getDb(): DatabaseType | null {
63	  return db;
64	}
65	
66	export function initMemoryDb(): void {
67	  const dbPath = path.join(resolveMemoryDir(), DB_FILENAME);
68	  db = new Database(dbPath);
69	  db.pragma("journal_mode = WAL");
70	  db.pragma("synchronous = NORMAL");
71	  createSchema(db);
72	}
73	
74	export function closeMemoryDb(): void {
75	  db?.close();
76	  db = null;
77	}
78	
79	/**
80	 * Sync master log → SQLite. Diff by content hash: insert new, delete removed.
81	 * Returns { inserted, deleted }.
82	 */
83	export function syncFactsToDb(userId: number | string): { inserted: number; deleted: number } {
84	  if (!db) return { inserted: 0, deleted: 0 };
85	
86	  const masterPath = masterFactsFile(userId);
87	  const parsed = parseMasterLog(masterPath);
88	
89	  // Get existing hashes in DB
90	  const existingRows = db.prepare("SELECT content_hash FROM facts").all() as Array<{ content_hash: string }>;
91	  const existingHashes = new Set(existingRows.map((r) => r.content_hash));
92	  const newHashes = new Set(parsed.map((f) => f.hash));
93	
94	  // Delete facts no longer in master
95	  const toDelete = [...existingHashes].filter((h) => !newHashes.has(h));
96	  if (toDelete.length > 0) {
97	    const del = db.prepare("DELETE FROM facts WHERE content_hash = ?");
98	    const delFts = db.prepare("DELETE FROM facts_fts WHERE content_hash = ?");
99	    const tx = db.transaction(() => {
100	      for (const h of toDelete) {
101	        del.run(h);
102	        delFts.run(h);
103	      }
104	    });
105	    tx();
106	  }
107	
108	  // Insert new facts
109	  const toInsert = parsed.filter((f) => !existingHashes.has(f.hash));
110	  if (toInsert.length > 0) {
111	    const ins = db.prepare(
112	      "INSERT OR IGNORE INTO facts (content_hash, text, topic, created_at) VALUES (?, ?, ?, ?)",
113	    );
114	    const insFts = db.prepare(
115	      "INSERT OR IGNORE INTO facts_fts (content_hash, text) VALUES (?, ?)",
116	    );
117	    const tx = db.transaction(() => {
118	      for (const f of toInsert) {
119	        ins.run(f.hash, f.text, f.topic, f.createdAt);
120	        insFts.run(f.hash, f.text);
121	      }
122	    });
123	    tx();
124	  }
125	
126	  return { inserted: toInsert.length, deleted: toDelete.length };
127	}
128	
129	/**
130	 * Insert a single fact (called after remember() writes to .md).
131	 */
132	export function insertFact(text: string, topic: string, createdAt: string): void {
133	  if (!db) return;
134	  const hash = contentHash(text);
135	  db.prepare("INSERT OR IGNORE INTO facts (content_hash, text, topic, created_at) VALUES (?, ?, ?, ?)").run(
136	    hash, text, topic, createdAt,
137	  );
138	  db.prepare("INSERT OR IGNORE INTO facts_fts (content_hash, text) VALUES (?, ?)").run(hash, text);
139	}
140	
141	/**
142	 * Delete facts by content hash (called after forget()).
143	 */
144	export function deleteFact(text: string): void {
145	  if (!db) return;
146	  const hash = contentHash(text);
147	  db.prepare("DELETE FROM facts WHERE content_hash = ?").run(hash);
148	  db.prepare("DELETE FROM facts_fts WHERE content_hash = ?").run(hash);
149	}
150	
151	/**
152	 * Check if a fact with the same content hash already exists.
153	 */
154	export function factExists(text: string): boolean {
155	  if (!db) return false;
156	  const hash = contentHash(text);
157	  const row = db.prepare("SELECT 1 FROM facts WHERE content_hash = ?").get(hash);
158	  return !!row;
159	}
160	
161	// ─── Embedding Cache ─────────────────────────────────────────────────────────
162	
