1	/**
2	 * Memory Recall — dynamically inject relevant topic shard facts into context
3	 * based on semantic similarity between the user message and topic representations.
4	 *
5	 * At init: builds a vector for each topic from "topic-name: keyword1, keyword2, ..."
6	 * Per turn: embeds user message, finds top matching topics above threshold,
7	 * reads those shards and returns facts to inject.
8	 */
9	
10	import { embedText, cosineSim, isEmbedRouterReady } from "./embed-router.js";
11	import { readTopicFacts, listTopicShards } from "./facts-store.js";
12	import { getTopicRules } from "./topic-rules.js";
13	import { hybridSearch, getDb, type HybridHit } from "./memory-db.js";
14	import { rerankRecallHits } from "./local-llm.js";
15	import { config } from "./config.js";
16	
17	// ─── Config ──────────────────────────────────────────────────────────────────
18	
19	/** Minimum cosine similarity to consider a topic relevant. */
20	const RECALL_THRESHOLD = 0.65;
21	/** Max topics to recall per turn. */
22	const RECALL_TOP_K = 3;
23	/** Max total facts to inject (avoid blowing up context). */
24	const RECALL_MAX_FACTS = 30;
25	/** Skip messages shorter than this (too short for meaningful embedding). */
26	const MIN_MSG_LENGTH = 10;
27	
28	// ─── State ───────────────────────────────────────────────────────────────────
29	
30	let topicVectors: Map<string, Float32Array> = new Map(); // topic name → vector
31	let initialized = false;
32	
33	// ─── Public API ──────────────────────────────────────────────────────────────
34	
35	/**
36	 * Build topic vectors from current topics.json rules.
37	 * Call after initEmbedRouter() so the model is loaded.
38	 */
39	export async function initMemoryRecall(): Promise<void> {
40	  if (!isEmbedRouterReady()) return;
41	  const rules = getTopicRules();
42	  topicVectors.clear();
43	  for (const rule of rules) {
44	    if (rule.topic === "misc") continue; // skip catchall
45	    // Build repr: "topic-name: keyword1, keyword2, keyword3"
46	    const repr = `${rule.topic}: ${rule.keywords.join(", ")}`;
47	    const vec = await embedText(repr);
48	    if (vec) topicVectors.set(rule.topic, vec);
49	  }
50	  initialized = true;
51	  console.log(`[memory-recall] ready: ${topicVectors.size} topic vectors`);
52	}
53	
54	export function isMemoryRecallReady(): boolean {
55	  return initialized && topicVectors.size > 0;
56	}
57	
58	export interface RecallHit {
59	  topic: string;
60	  score: number;
61	  facts: string[]; // stripped fact text
62	}
63	
64	/**
65	 * Given a user message, find semantically relevant topic shards and return
66	 * their facts. Returns empty array if nothing matches or module not ready.
67	 * `recentFacts` (optional) is the set of facts already in the preamble tail —
68	 * these are excluded from recall results to avoid duplication.
69	 * `excludeTopics` (optional) skips topics already covered by wiki retrieval.
70	 */
71	export async function recallRelevantFacts(
72	  userMsg: string,
73	  userId: number | string,
74	  recentFacts?: Set<string>,
75	  excludeTopics?: Set<string>,
76	  /** If provided, only consider these topics (scope filter for specialists). */
77	  includeTopics?: Set<string>,
78	  /** Override threshold (e.g. lower when scope already narrows candidates). */
79	  threshold = RECALL_THRESHOLD,
80	): Promise<RecallHit[]> {
81	  if (!initialized || topicVectors.size === 0) return [];
82	  if (userMsg.trim().length < MIN_MSG_LENGTH) return [];
83	
84	  // ─── Hybrid path: use SQLite FTS5 + vector when DB is available ────────
85	  if (getDb()) {
86	    const hits = await hybridSearch(userMsg, {
87	      topK: RECALL_MAX_FACTS,
