#!/usr/bin/env node
/**
 * sync-skills-to-repo.mjs — Copy tracked default-skills FROM local skill dir TO repo.
 * Only syncs skills already in default-skills/ (won't add new ones).
 * Called by .githooks/pre-commit automatically.
 */
import { readFileSync, writeFileSync, readdirSync, existsSync, mkdirSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import os from "node:os";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "..");
const defaultSkillsDir = path.join(repoRoot, "default-skills");
const kiroSkillsDir = path.join(os.homedir(), ".kiro", "skills");

if (!existsSync(defaultSkillsDir)) process.exit(0);

const tracked = readdirSync(defaultSkillsDir, { withFileTypes: true })
  .filter(e => e.isDirectory())
  .map(e => e.name);

let updated = 0;
for (const name of tracked) {
  const srcFile = path.join(kiroSkillsDir, name, "SKILL.md");
  const dstFile = path.join(defaultSkillsDir, name, "SKILL.md");
  if (!existsSync(srcFile)) continue;
  const src = readFileSync(srcFile, "utf8");
  const dst = existsSync(dstFile) ? readFileSync(dstFile, "utf8") : "";
  if (src === dst) continue;
  mkdirSync(path.dirname(dstFile), { recursive: true });
  writeFileSync(dstFile, src, "utf8");
  updated++;
}

if (updated > 0) console.log(`[sync-skills] ${updated} skill(s) updated in default-skills/`);

