import { spawn } from "node:child_process";
import fs from "node:fs/promises";
import path from "node:path";
import { config } from "./config.js";
import { detectAgentConfigDir } from "./memory.js";

/**
 * Backup module — mirrors AIMemory + <AGENT_CONFIG_DIR>/* into
 * `config.backupRepoDir` with robocopy, commits with a timestamped message,
 * and pushes to origin.
 *
 * AGENT_CONFIG_DIR is detected via the same heuristic as the preamble
 * Environment block: ~/.kiro for Kiro, ~/.codex for Codex, ~/.claude for
 * Claude, or whatever $AGENT_CONFIG_DIR overrides. Env var wins.
 *
 * Destination subdir naming: the backup-repo subdir matches the agent —
 * "kiro/" for Kiro, "codex/" for Codex, "claude/" for Claude. This makes
 * the backup repo layout self-documenting when each machine pushes to its
 * own private repo (recommended setup). For the legacy "one shared repo
 * fed by multiple machines" scenario, set BACKUP_AGENT_DIR_NAME=kiro on
 * every box to force the old behavior (all agents write to kiro/, last
 * push wins per tree).
 *
 * Usage:
 *   const res = await runBackup();
 *   if (!res.ok) throw new Error(res.error);
 *   res.summary  // "facts +3 lines, skills no change, ..."
 *   res.commit   // short sha or "" if nothing to commit
 *
 * Design notes:
 * - robocopy /MIR is idempotent and fast; git commit only stages what actually
 *   changed. "No changes" is a normal outcome, not an error.
 * - .env* is excluded by robocopy /XF AND by .gitignore (belt+suspenders).
 * - We shell out instead of using simple-git / a JS git lib to keep the
 *   dependency footprint zero — git + robocopy are already on the box.
 * - robocopy exit codes 0-7 are success (bits: 1=copied, 2=extra, 4=mismatch);
 *   8+ is real failure. Classic Windows gotcha.
 */

export interface BackupResult {
  ok: boolean;
  /** Short commit sha, or "" if nothing changed (and thus no commit). */
  commit: string;
  /** "No changes" | "facts +3 lines, skills mirror, kiro/agents +1 file". */
  summary: string;
  /** Number of files changed in the commit (0 if no commit). */
  filesChanged: number;
  /** Seconds elapsed for the whole run. */
  elapsedSec: number;
  /** Populated when ok=false. */
  error?: string;
}

/** robocopy /XF glob patterns — excluded regardless of .gitignore. */
const ROBOCOPY_EXCLUDE_FILES = [".env", ".env.*", "*.env", "*.log"];

/** One mirror job: copy `src` recursively to `dst`. */
interface MirrorJob {
  src: string;
  dst: string;
  /** For logging / error attribution. */
  label: string;
  /**
   * Subdirectories to exclude via robocopy /XD. Paths are resolved relative
   * to `src` and passed as absolute paths (most reliable on Windows).
   * Use for content too large / too sensitive / out-of-scope for the backup
   * repo — e.g. raw video transcripts.
   */
  excludeDirs?: string[];
  /** If set, only copy files matching this pattern (e.g. "preamble.md"). Disables /MIR. */
  fileFilter?: string;
}

/**
 * Resolve the subdir name under the backup repo for agent config files.
 * Default: matches the detected agent ("kiro" / "codex" / "claude") so the
 * backup repo layout is self-documenting.
 * Override: set BACKUP_AGENT_DIR_NAME=kiro to force the legacy "all agents
 * share one kiro/ tree" behavior (needed for a single backup repo shared
 * across Kiro + Codex machines).
 */
export function detectAgentDstName(): string {
  const override = process.env.BACKUP_AGENT_DIR_NAME;
  if (override && override.trim() !== "") return override.trim();
  const agent = (config.agent?.command ?? "").toLowerCase();
  if (agent.includes("codex")) return "codex";
  if (agent.includes("claude")) return "claude";
  if (agent.includes("kiro")) return "kiro";
  return "kiro"; // fallback — same as old hardcoded value
}

// Exported for smoke tests; normal callers should use runBackup().
export function buildJobs(repoDir: string): MirrorJob[] {
  const agentHome = detectAgentConfigDir();
  const agentDst = detectAgentDstName();
  return [
    // Long-term memory (facts, schedules, sessions, oldSessions).
    // transcripts/ is intentionally excluded — raw video transcripts can be
    // large and may contain copyrighted content; keep local-only.
    {
      label: "AIMemory",
      src: config.memoryDir,
      dst: path.join(repoDir, "AIMemory"),
      excludeDirs: ["transcripts"],
    },
    // Agent config — source is ~/.kiro or ~/.codex or ~/.claude depending on
    // the detected agent; destination subdir matches (kiro / codex / claude).
    // Override both with AGENT_CONFIG_DIR + BACKUP_AGENT_DIR_NAME if needed.
    {
      label: `agent/agents`,
      src: path.join(agentHome, "agents"),
      dst: path.join(repoDir, agentDst, "agents"),
    },
    {
      label: `agent/settings`,
      src: path.join(agentHome, "settings"),
      dst: path.join(repoDir, agentDst, "settings"),
    },
    {
      label: `agent/steering`,
      src: path.join(agentHome, "steering"),
      dst: path.join(repoDir, agentDst, "steering"),
    },
    {
      label: `agent/powers`,
      src: path.join(agentHome, "powers"),
      dst: path.join(repoDir, agentDst, "powers"),
    },
    {
      label: `agent/skills`,
      src: path.join(agentHome, "skills"),
      dst: path.join(repoDir, agentDst, "skills"),
    },
    // Specialist preambles only (AGENTS.md/CLAUDE.md are auto-generated on restart).
    {
      label: "specialists/preamble",
      src: path.join(config.sessionCwd, "specialists"),
      dst: path.join(repoDir, "specialists"),
      fileFilter: "preamble.md",
    },
  ];
}

