2	 * enrichment.ts — Shared dynamic enrichment logic (NotebookLM routing,
3	 * wiki retrieval, memory recall) used by both the main agent turn and
4	 * specialist proxy/delegation.
5	 */
6	
7	import { isEmbedRouterReady, routeByEmbedding } from "./embed-router.js";
8	import { isWikiRetrievalReady, retrieveWikiPages, formatWikiBlock } from "./wiki-retrieval.js";
