13	// ─── Types ─────────────────────────────────────────────────────────────────
14	
15	/** Scope filter — limits enrichment to a specialist's domain. */
16	export interface EnrichmentScope {
17	  /** Only match these wiki page slugs. */
18	  wikiPages?: string[];
19	  /** Only match notebooks whose title is in this list. */
20	  notebooks?: string[];
