27	/**
28	 * Run the three enrichment stages and return a prefix string to prepend
29	 * to the user message. If `scope` is provided, results are filtered to
30	 * only the specified domain (for specialist use).
31	 */
32	export async function runEnrichment(
33	  userMsg: string,
34	  userId: number | string,
35	  recentFacts?: Set<string>,
36	  scope?: EnrichmentScope,
37	): Promise<string> {
38	  let prefix = "";
39	
40	  // When scope is active, the whitelist already narrows candidates — lower threshold
41	  const scopedThreshold = scope ? 0.45 : undefined;
42	
43	  // 1. NotebookLM routing
44	  if (isEmbedRouterReady()) {
45	    try {
46	      const titleFilter = scope?.notebooks?.length
47	        ? new Set(scope.notebooks)
48	        : undefined;
49	      const hits = await routeByEmbedding(userMsg, titleFilter, scopedThreshold);
50	      if (hits.length > 0) {
51	        const hitLines = hits.map(
52	          (h) => `- 《${h.title}》(id=${h.notebookId}, score=${h.score.toFixed(3)}, strategy=${h.strategy})`,
53	        );
54	        prefix +=
55	          `[NotebookLM routing — embedding match]\n` +
56	          `以下 notebook 與使用者問題語意相近，請用 notebook_query 查詢後以該 strategy 格式回答：\n` +
57	          hitLines.join("\n") +
58	          `\n[End routing]\n\n`;
59	      }
60	    } catch (err) {
61	      console.warn("[enrichment] notebooklm routing failed:", err);
62	    }
63	  }
64	
65	  // 2. Wiki retrieval
66	  const wikiHitSlugs = new Set<string>();
67	  if (isWikiRetrievalReady()) {
68	    try {
69	      const slugFilter = scope?.wikiPages?.length
70	        ? new Set(scope.wikiPages)
71	        : undefined;
72	      const hits = await retrieveWikiPages(userMsg, slugFilter, scopedThreshold);
73	      // Dedup: skip wiki pages already injected in a prior turn
74	      const fresh = recentFacts
75	        ? hits.filter((h) => !recentFacts.has(`wiki:${h.slug}`))
76	        : hits;
77	      if (fresh.length > 0) {
78	        for (const h of fresh) {
