session.inflight = true;
sessions.resetTurn(session);
petState("thinking");

let continuationPlan: ContinuationPlan | null = null;
let continueTokenFired = false;
let pendingRestartReason: string | null = null;

if (!continuationContext) {
  session.history.push({ role: "user", text, timestamp: Date.now() });
}
session.charsIn += text.length;

let promptText = text;
if (!session.preambleInjected && session.memoryPreamble) {
  promptText = session.memoryPreamble + text;
  session.preambleInjected = true;
}

const replyToId = ctx.message?.message_id;
const placeholderText = continuationContext
  ? `↻ Continuing (${continuationContext.turnIndex}/${continuationContext.maxTurns}) toward goal…`
  : "Thinking…";
let placeholder: { message_id: number } | undefined;
if (!isRelay && !isSilentMeta) {
  try {
    placeholder = await ctx.reply(placeholderText, {
      ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
    });
  } catch (err: any) {
    const desc = err?.description || err?.error?.description || "";
    if (replyToId && /message to be replied not found/i.test(desc)) {
      placeholder = await ctx.reply(placeholderText);
    } else {
      throw err;
    }
  }
}

let lastEditAt = 0;
let lastRendered = "";
let editTimer: NodeJS.Timeout | null = null;
let throttledSnapshotLogged = false;
let turnHitRateLimit = false;
let turnFinalized = false;

const editNow = async () => {
  if (!placeholder) return;
  if (rateLimitedUntil() > Date.now()) {
    turnHitRateLimit = true;
    if (!throttledSnapshotLogged) {
      throttledSnapshotLogged = true;
      const snapshot = (session.buffer || "").trim();
      const preview = snapshot.length > 800
        ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
        : snapshot;
      console.warn(
        `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
      );
    }
    return;
  }
  const { content, parseMode } = renderReply(session, false, scheduleParsers);
  if (content === lastRendered) return;
  lastRendered = content;
  lastEditAt = Date.now();
  try {
    await ctx.api.editMessageText(chatId, placeholder.message_id, content,
      parseMode ? { parse_mode: parseMode } : {});
  } catch {
    // parse error or identical content — retry without parse_mode (strip HTML tags)
    try {
      await ctx.api.editMessageText(chatId, placeholder.message_id,
        content.replace(/<[^>]+>/g, ""));
    } catch { /* identical or rate-limited; ignore */ }
  }
};

const unregisterRecovery = isRelay || isSilentMeta ? () => {} : onRateLimitRecovery(() => {
  if (turnFinalized) {
    console.log(
      `[rate-limit] chat ${chatId} recovery callback suppressed — turn already finalized`
    );
    return;
  }
  throttledSnapshotLogged = false;
  console.log(
    `[rate-limit] chat ${chatId} resuming edits — pushing latest buffer (${(session.buffer || "").length} chars)`
  );
  lastRendered = "";
  return editNow();
});

session.onUpdate = isRelay
  ? undefined
  : () => {
      const elapsed = Date.now() - lastEditAt;
      if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
        editNow();
      } else if (!editTimer) {
        editTimer = setTimeout(() => {
          editTimer = null;
          editNow();
        }, STREAM_EDIT_INTERVAL_MS - elapsed);
      }
    };


try {
  const { stopReason } = await session.client.prompt(promptText);
  if (editTimer) {
    clearTimeout(editTimer);
    editTimer = null;
  }
  turnFinalized = true;

  if (session.buffer) {
    session.history.push({ role: "assistant", text: session.buffer, timestamp: Date.now() });
  }

  const toolsPrefix = session.toolLog.length
    ? session.toolLog.slice(-5).join("\n") + "\n\n"
    : "";

  // Extract relay tokens before ab7 (it doesn't know them).
  const relayTokens: { target: string; text: string }[] = [];
  const relayFileTokens: { target: string; path: string }[] = [];
  const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];
  const relayResultTokens: { target: string; payload: ResultPayload }[] = [];
  const parallelDelegateTasks: ParallelTask[] = [];
  const RELAY_RE = /<<RELAY:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
  const RELAY_FILE_RE = /<<RELAY_FILE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
  const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
  const RELAY_RESULT_RE = /<<RELAY_RESULT:\s*([^|>\r\n]+?)\s*\|\s*(\{[^>\r\n]+?\})\s*>>/g;
  const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
  {
    const { masked, restore } = maskCodeRegions(session.buffer);
    const stripped = masked
      .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {
        let p: DelegatePayload;
        try {
          p = JSON.parse(body) as DelegatePayload;
          if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
        } catch {
          p = { id: `rd_${Date.now()}`, goal: body.trim() };
        }
        if (p.goal) relayDelegateTokens.push({ target: target.trim(), payload: p });
        return "";
      })
      .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {
        try {
          const p = JSON.parse(json) as ResultPayload;
          relayResultTokens.push({ target: target.trim(), payload: p });
        } catch { /* malformed JSON — ignore */ }
        return "";
      })
      .replace(RELAY_RE, (_m, target: string, msg: string) => {
        relayTokens.push({ target: target.trim(), text: msg.trim() });
        return "";
      })
      .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {
        relayFileTokens.push({ target: target.trim(), path: p.trim() });
        return "";
      })
      .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {
        parallelDelegateTasks.push({
          taskId: taskId.trim(),
          target: target.trim(),
          payload: { id: taskId.trim(), goal: prompt.trim() },
        });
        return "";
      });
    session.buffer = restore(stripped);
  }

  // Fallback: recover RELAY_DELEGATE from streaming captures
  if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {
    const RELAY_DELEGATE_RE2 = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    for (const raw of session._streamingDelegates) {
      RELAY_DELEGATE_RE2.lastIndex = 0;
      const m = RELAY_DELEGATE_RE2.exec(raw);
      if (m) {
        let p: DelegatePayload;
        try {
          p = JSON.parse(m[2]) as DelegatePayload;
          if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
        } catch {
          p = { id: `rd_${Date.now()}`, goal: m[2].trim() };
        }
        if (p.goal) relayDelegateTokens.push({ target: m[1].trim(), payload: p });
      }
    }
    if (relayDelegateTokens.length > 0) {
      console.log(`[chat ${chatId}] relay delegate recovered from streaming capture (${relayDelegateTokens.length} token(s))`);
    }
  }

  // <<RELAY_DONE>>
  const { masked: maskedForDone, restore: restoreDone } = maskCodeRegions(session.buffer);
  const relayDone = /<<RELAY_DONE>>/i.test(maskedForDone);

