/**
 * MCP Client Pool — connects to configured MCP servers (stdio transport),
 * aggregates their tool schemas, and routes tool_use calls to the right server.
 *
 * Used by DirectProvider's tool loop. ACP mode doesn't need this (Kiro CLI
 * manages its own MCP connections).
 */
import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import { readFile } from "node:fs/promises";
import path from "node:path";

export interface McpServerConfig {
  command: string;
  args?: string[];
  env?: Record<string, string>;
  disabled?: boolean;
}

export interface ToolSchema {
  name: string;
  description?: string;
  inputSchema: Record<string, unknown>;
  /** Which MCP server owns this tool. */
  _server: string;
}

interface ConnectedServer {
  name: string;
  client: Client;
  transport: StdioClientTransport;
  tools: ToolSchema[];
}

export class McpPool {
  private servers: ConnectedServer[] = [];
  private toolIndex = new Map<string, ConnectedServer>();

  /** Connect to all enabled MCP servers from a config object. */
  async connectAll(configs: Record<string, McpServerConfig>, extraEnv?: Record<string, string>): Promise<void> {
    const entries = Object.entries(configs).filter(([, c]) => !c.disabled);
    const results = await Promise.allSettled(
      entries.map(([name, cfg]) => this.connectOne(name, cfg, extraEnv)),
    );
    for (let i = 0; i < results.length; i++) {
      if (results[i].status === "rejected") {
        console.warn(`[mcp-pool] failed to connect "${entries[i][0]}":`, (results[i] as PromiseRejectedResult).reason?.message ?? results[i]);
      }
    }
  }

  private async connectOne(name: string, cfg: McpServerConfig, extraEnv?: Record<string, string>): Promise<void> {
    const transport = new StdioClientTransport({
      command: cfg.command,
      args: cfg.args ?? [],
      env: { ...process.env, ...cfg.env, ...extraEnv } as Record<string, string>,
    });
    const client = new Client({ name: `bridge-pool-${name}`, version: "1.0.0" });
    await client.connect(transport);

    const { tools } = await client.listTools();
    const schemas: ToolSchema[] = (tools ?? []).map((t) => ({
      name: t.name,
      description: t.description,
      inputSchema: t.inputSchema as Record<string, unknown>,
      _server: name,
    }));

    const server: ConnectedServer = { name, client, transport, tools: schemas };
    this.servers.push(server);
    for (const t of schemas) {
      this.toolIndex.set(t.name, server);
    }
    console.log(`[mcp-pool] connected "${name}" — ${schemas.length} tools`);
  }

  /** All tool schemas across all connected servers (for LLM API tools param). */
  listTools(): ToolSchema[] {
    return this.servers.flatMap((s) => s.tools);
  }

  /** Execute a tool call, routing to the correct MCP server. */
  async callTool(name: string, args: Record<string, unknown>): Promise<{ content: unknown[]; isError?: boolean }> {
    const server = this.toolIndex.get(name);
    if (!server) {
      return { content: [{ type: "text", text: `Error: tool "${name}" not found in any MCP server` }], isError: true };
    }
    const result = await server.client.callTool({ name, arguments: args });
    return { content: result.content as unknown[], isError: !!result.isError };
  }

  /** Gracefully close all connections. */
  async close(): Promise<void> {
    await Promise.allSettled(this.servers.map((s) => s.client.close()));
    this.servers = [];
    this.toolIndex.clear();
  }

  get size(): number {
    return this.servers.length;
  }
}

/**
 * Load MCP server configs from ~/.kiro/settings/mcp.json.
 * Also includes the bridge's own memory MCP server.
 */
export async function loadMcpConfigs(): Promise<Record<string, McpServerConfig>> {
  const settingsPath = path.join(
    process.env.AGENT_CONFIG_DIR ?? path.join(process.env.USERPROFILE ?? process.env.HOME ?? "", ".kiro"),
    "settings",
    "mcp.json",
  );
  try {
    const raw = await readFile(settingsPath, "utf8");
    const parsed = JSON.parse(raw);
    const configs: Record<string, McpServerConfig> = parsed.mcpServers ?? {};
    // Always include the bridge's own memory MCP server
    if (!configs["memory"]) {
      configs["memory"] = {
        command: "node",
        args: [path.resolve("dist/mcp-memory.js")],
      };
    }
    return configs;
  } catch (err) {
    console.warn(`[mcp-pool] could not load ${settingsPath}:`, (err as Error).message);
    // Fallback: just the memory server
    return {
      memory: { command: "node", args: [path.resolve("dist/mcp-memory.js")] },
    };
  }
}
